                            </div>
                        </div>
                    </span>
                    <a href="javascript:;" :title="$t('WeekRoadMap')"
                        :class="['p-action-btn', 'text-white', 'RM_zoomWeeks', { active: activeZoom === 'Week' }]"
                        @click="setZoom('Week')">
                        <em class="fa fa-calendar"></em><br />{{ $t('WeekRoadMap') }}
                    </a>
                    <a href="javascript:;" :title="$t('MonthRoadMap')" 
                        :class="['p-action-btn', 'text-white', 'RM_zoomMonths', { active: activeZoom === 'Month' }]"
                        @click="setZoom('Month')">
                        <em class="fa fa-calendar"></em><br />{{ $t('MonthRoadMap') }}
                    </a>
                    <a href="javascript:;" :title="$t('QuarterRoadMap')" 
                        :class="['p-action-btn', 'text-white', 'RM_zoomQuarters', { active: activeZoom === 'Quarter' }]"
                        @click="setZoom('Quarter')">
                        <em class="fa fa-calendar"></em><br />{{ $t('Quarter') }}
                    </a>
                    <a href="javascript:;" :title="$t('YearsRoadMap')" 
                        :class="['p-action-btn', 'text-white', 'RM_zoomYears', { active: activeZoom === 'Year' }]"
                        @click="setZoom('Year')">
                        <em class="fa fa-calendar"></em><br />{{ $t('YearsRoadMap') }}
                    </a>                    
                    <span class="user-guide">
                        <a class="ancuserguide p-action-btn text-white userguideicon"  data-toggle="collapse" href="javascript:void(0)"
                            role="button" aria-expanded="false" aria-controls="collapseExample"
                            @click="ShowUserGuide()"> <em class="fa fa-file-text-o"></em><br />{{ $t('UserGuide') }}
                        </a>
                    </span>
                </span>
                <span class="p-actions float-right">
                    <div class="d-inline-block RM_Setting">
                        <a href="javascript:;" @click="TaskColorScheme" :title="$t('Task') + ' ' + $t('ColorScheme')"
                            class="p-action-btn text-white showRM_Setting">
                            <em class="fa fa-tasks"></em><br />{{ $t('Task') }} {{ $t('ColorScheme') }}
                        </a>
                        <div class="Rm_drop" v-if="IsTaskColorScheme">
                            <div>
                                <div class="SquareColor Active pullleft" style="position:initial;"></div>
                                <span>{{ $t('Active') }}</span>
                            </div>
                            <div>
                                <div class="SquareColor Cancelled pullleft" style="position:initial;"></div>
                                <span>{{ $t('Cancelled') }}</span>
                            </div>
                            <div>
                                <div class="SquareColor Closed pullleft" style="position:initial;"></div>
                                <span>{{ $t('Closed') }}</span>
                            </div>
                            <div>
                                <div class="SquareColor Completed pullleft" style="position:initial;"></div>
                                <span>{{ $t('Completed') }}</span>
                            </div>
                            <div>
                                <div class="SquareColor Inactive pullleft" style="position:initial;"></div>
                                <span>{{ $t('Inactive') }}</span>
                            </div>
                            <div>
                                <div class="SquareColor Inprogress pullleft" style="position:initial;"></div>
                                <span>{{ $t('Inprogress') }}</span>
                            </div>
                            <div>
                                <div class="SquareColor Pending pullleft" style="position:initial;"></div>
                                <span>{{ $t('Pending') }}</span>
                            </div>
                        </div>
                    </div>
                </span>
                <span class="collapse-head-btns">
                    <a href="javascript:;" class="collapse-btns"><i class="fa fa-angle-up text-white"></i></a>
                </span>
                <span class="float-right text-white mt-3 mr-2 legends-rmap">
                    <div class="mr-2 d-inline-block">
                        <span class="colorboxsquare legend-milestone"></span>{{ $t('Milestone') }}
                    </div>
                    <div class="mr-2 d-inline-block">
                        <span class="bg-stage colorboxsquare"></span>{{ $t('Stage') }}
                    </div>
                    <div class="mr-2 d-inline-block">
                        <span class="bg-info colorboxsquare"></span>{{ $t('Phase') }}
                    </div>
                </span>
            </div>
            <div class="col-md-12 p-0">
                <div class="container-fluid p-0">
                    <div class="border px-3 pt-2 for-pt-legends">
                        <div class="row">
                            <div class="col-lg-3">
                                <div class="form-group">
                                    <label class="w-100 mb-2">{{ $t('Filter') }} {{ $t('Type') }}:</label>
                                    <div class="rad_value">
                                        <label class="cogfiglbl form-check form-check-inline">
                                            <div class="custom-control custom-radio custom-control-inline">
                                                <input class="custom-control-input" name="SearchCreteira" id="RadioSelectProject"
                                                    value="Project" type="radio" v-model="selectedRoadType"
                                                    @change="onRoadTypeChange">
                                                <label class="custom-control-label" for="RadioSelectProject"></label>
                                            </div>{{ $t('Project') }}
                                        </label>
                                        <label class="cogfiglbl form-check form-check-inline">
                                            <div class="custom-control custom-radio custom-control-inline">
                                                <input class="custom-control-input" name="SearchCreteira"
                                                    id="RadioSelectDateRange" value="DateRange" type="radio"
                                                    v-model="selectedRoadType" @change="onRoadTypeChange">
                                                <label class="custom-control-label" for="RadioSelectDateRange"></label>
                                            </div>{{ $t('DateRange') }}
                                        </label>
                                    </div>
                                </div>
                            </div>
                            <div class="col-lg-4" v-if="isDateRange">
                                <div class="form-group">
                                    <label class="mb-1">{{ $t('Project') }}:</label>
                                    <div class="input-group multiselect-group">                                    
                                        <multiselect
                                            class="form-control p-0"
                                            placeholder="Select Projects" :max-height="150"
                                            v-model="selectedProjects" label="label"
                                            track-by="value" :limit="2" mode="tag"
                                            :options="projectOptions" :multiple="true"
                                            :taggable="true" @input="onProjectChange">
                                        </multiselect>
                                    </div>
                                </div>
                            </div>
                            <div class="col-lg-3" v-if="!isDateRange">
                                <div class="form-group">
                                    <label class="mb-1">{{ $t('SelectDate') }}:</label>
                                    <div class="row">
                                        <div class="col-12 col-md-6 float-left mb-2 mb-md-0">
                                            <div class="input-group">
                                                <v-date-picker v-bind:name="'StartDate'" :minute-increment="5"
                                                    class="timedate input-group" v-model="RequestStartDate">
                                                    <template v-slot="{ inputValue, inputEvents, togglePopover }">
                                                        <input placeholder="MM/DD/YYYY" class="form-control"
                                                            :value="inputValue" v-on="inputEvents" />
                                                        <div class="input-group-append" v-on:click="togglePopover">
                                                            <span class="input-group-text">
                                                                <em class="fa fa-calendar"></em>
                                                            </span>
                                                        </div>
                                                    </template>
                                                </v-date-picker>
                                            </div>
                                        </div>
                                        <div class="col-12 col-md-6 float-left">
                                            <div class="input-group">
                                                <v-date-picker v-bind:name="'EndDate'" :minute-increment="5"
                                                    class="timedate input-group" v-model="RequestEndDate">
                                                    <template v-slot="{ inputValue, inputEvents, togglePopover }">
                                                        <input placeholder="MM/DD/YYYY" class="form-control"
                                                            :value="inputValue" v-on="inputEvents" />
                                                        <div class="input-group-append" v-on:click="togglePopover">
                                                            <span class="input-group-text">
                                                                <em class="fa fa-calendar"></em>
                                                            </span>
                                                        </div>
                                                    </template>
                                                </v-date-picker>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                            <div class="col-lg-3">
                                <div class="form-group">
                                    <label class="mb-1">&nbsp;</label>
                                    <div class="row">
                                        <div class="col-12">
                                            <a title="Search" id="aSearch" href="javascript:;" @click="SearchRoadMap"
                                                class="btn btn-success mr-1 px-4" data-toggle-tooltip="tooltip"
                                                data-original-title="Search">
                                                <em class="fa fa-search"></em>
                                            </a>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
           </div>
        </div>
        <div class="clearfix"></div>
        <div v-if="roadMapData && roadMapData.length > 0" class="listing" id="divresource">
            <RoadMapCalendar :roadMapData="roadMapData" :fromDate="fromDate" :toDate="toDate" :activeZoom="activeZoom"
                :selectedSettings="selectedSettings" :projectList="projectList"  :key="reloadekey"/>
        </div>
        
        <div v-if="isUserGuide">
            <RoadMapUserGuide />
        </div>
        <div v-if="isProject">
          <AddProject :ProjectId="ProjectId" :Type="Type" />
        </div>
    </section>
</template>

<script>
import DataService from '../../../services/DataService';
import RoadMapCalendar from './RoadMapCalendar.vue';
import RoadMapUserGuide from './RoadMapUserGuide.vue';
import AddProject from '../../../components/Modal/AddProject.vue';
import Vue from 'vue';
export const EventBus = new Vue();
export default {
    name: "RoadMapView",
    components: {
        RoadMapCalendar,RoadMapUserGuide,AddProject
    },
    props:{
        projectId:{
            type:String
        }
    },
    data() {
        return {
            selectedRoadType: 'Project',
            isUserGuide:false,
            isPhase:false,
            isStage:false,
            reloadekey:'',
            isSideBar:false,
            isProject:false,
            isDateRange: true,
            projectOptions: [],
            selectedProjects: [],
            RequestStartDate: '',
            RequestEndDate: '',
            IsTaskColorScheme: false,
            isRdSetting: false,
            selectedSettings: ['P', 'S', 'TM'],
            activeZoom: 'Week',
            roadMapData: [],
            projectList: [],
            fromDate: new Date(),
            toDate: new Date(),
            isLoading: false,
            hasSearched: false,
            toggleUserGuide: 'd-none',
            ProjectId:0,
            Type:'',
            reqFrom:'',
        }
    },
    computed: {
        isPhaseSelected() {
            return this.selectedSettings.includes('P');
        },
        isStageSelected() {
            return this.selectedSettings.includes('S');
        }
    },
    created() {        
        this.loadProjectList();
        this.initializeDates();
        this.reqFrom=this.$route.params.Type;
        this.ProjectId=encodeURIComponent(this.$route.params.ProjectId); 
    },    
    mounted() {
        document.addEventListener('click', this.handleClickOutside);        
        const queryParams = this.$route.query;
        if (queryParams.prid) {
            this.selectedRoadType = 'Project';
            this.isDateRange = true;
            const projectIds = queryParams.prid.split(',');
            this.$nextTick(() => {
                this.selectedProjects = this.projectOptions.filter(p => projectIds.includes(String(p.value)));
            });
        } else if (queryParams.StartDate && queryParams.EndDate) {
            this.selectedRoadType = 'DateRange';
            this.isDateRange = false;
            this.RequestStartDate = new Date(parseInt(queryParams.StartDate) * 1000);
            this.RequestEndDate = new Date(parseInt(queryParams.EndDate) * 1000);
        }
        if (queryParams.show) {
            this.selectedSettings = queryParams.show.split(',');
        }
        if (queryParams.prid || (queryParams.StartDate && queryParams.EndDate)) {
            this.SearchRoadMap();
        }        
        this.$root.$on('call-SearchRoadMapCall', (payload) => {            
            if (payload.action === 'update' || payload.action ===  'create') {
                this.reqFrom ='RoadMap'
                this.ProjectId=payload.ProjectId;
                this.SearchRoadMap();
                }
            });
    },
    beforeDestroy() {
        document.removeEventListener('click', this.handleClickOutside);
        this.$root.$off('call-UpdateRecrds');
    },
    methods: {
        UpdateOverView(){
            debugger
            this.reqFrom ='RoadMap'
             this.SearchRoadMap();
        },
        editProjectDetailHandler(projectId){            
            this.isLoading = true;
            this.Type='Deatils';
            this.ProjectId=projectId;
            this.isProject=true;
            setTimeout(function () {
                $("#modalAddProject").modal("show");
            }, 1000);
            this.isLoading = false;
        },
        initializeDates() {
            const today = new Date();
            const dayOfWeek = today.getDay();
            const diffToMonday = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
            const monday = new Date(today);
            monday.setDate(today.getDate() + diffToMonday);
            monday.setHours(0, 0, 0, 0);            
            const endDate = new Date(monday);
            endDate.setMonth(endDate.getMonth() + 2);
            const lastDayOfWeek = endDate.getDay();
            const diffToSunday = lastDayOfWeek === 0 ? 0 : 7 - lastDayOfWeek;
            endDate.setDate(endDate.getDate() + diffToSunday);            endDate.setHours(0, 0, 0, 0);
            
            this.fromDate = monday;
            this.toDate = endDate;
        },
        loadProjectList() {            
            DataService.RoadProjectListing().then((response) => {
                if (response.data.length>0) { 
                    this.projectOptions = response.data.map(p => ({
                        value: p.projectId,
                        label: p.projectName
                    }));
                    if(this.reqFrom=='RoadMap')
                    {
                        this.selectedProjects=this.projectOptions.filter(x=>x.value == this.ProjectId);
                        this.SearchRoadMap();
                    }
                }
            }).catch((error) => {
                console.error('Error loading projects:', error);
            });
        },
        onRoadTypeChange() {
            if (this.selectedRoadType === 'Project') {
                this.isDateRange = true;
            } else if (this.selectedRoadType === 'DateRange') {
                this.isDateRange = false;
            }
        },
        onProjectChange() {           
            if (this.selectedProjects.length > 5) {
                this.ShowAlert(this.$t('RoadMapProjectSelect'), "warning", true, this.$t('Alert'));
                this.selectedProjects = this.selectedProjects.slice(0, 5);
            }
            this.reloadData();
        },
        reloadData() {
            debugger
            let selectProjectData = this.roadMapData.filter(r =>
            this.selectedProjects.some(selected => parseInt(selected.value) == r.projectId)
            ); 
            this.roadMapData=selectProjectData;
        },
        callbackfunction()
        {
            debugger
            this.reloadekey++;
        },
        SearchRoadMap() {   
            //debugger      
            if (this.selectedRoadType === 'Project') {
                if (!this.selectedProjects || this.selectedProjects.length === 0) {
                    this.roadMapData=[];
                    this.ShowAlert(this.$t('SelectProject'), "warning", true, this.$t('Alert'));
                    return;
                }
            } else {
                if (!this.RequestStartDate || !this.RequestEndDate) {
                    this.ShowAlert(this.$t('SelectDateRange'), "warning", true, this.$t('Alert'));
                    return;
                }
            }
            
            this.isLoading = true;
            this.hasSearched = true;
            var  projectIds='';
            var startDate='';
            var endDate='';
          if(this.reqFrom !='RoadMap')
          {
             projectIds = this.selectedRoadType === 'Project'
                ? encodeURIComponent(this.selectedProjects.map(p => p.value).join(','))
            : '';
                        
             startDate = this.selectedRoadType === 'DateRange' 
                ? Math.floor(new Date(this.RequestStartDate).getTime() / 1000)
                : '';
            
            const endDate = this.selectedRoadType === 'DateRange'
                ? Math.floor(new Date(this.RequestEndDate).getTime() / 1000)
                : '';
            
            const searchType = this.selectedRoadType === 'Project' ? 'project' : 'dateRange';
            const showParams = this.selectedSettings.join(',');
            
          }
          else
          {
            projectIds =this.ProjectId;
          }
            // Build URL parameters
            let params = `projectid=${projectIds}&type=both&startDate=${startDate}&endDate=${endDate}&from=`;            
            // Make API call inline - using DataService method
            DataService.GetRoadMapData(params).then((response) => {      
                if (response.data && response.data.roadMapData) {
                    this.roadMapData = response.data.roadMapData.roadMap;
                    this.projectList = response.data.roadMapData.listProjectResult || [];
                    if (response.data.roadMapData.startDate && response.data.roadMapData.endDate) {
                        this.fromDate = new Date(response.data.roadMapData.startDate * 1000);
                        this.toDate = new Date(response.data.roadMapData.endDate * 1000);
                    }
                } 
                else {
                    this.roadMapData = [];
                    this.ShowAlert(this.$t('No_Record_Found'), "warning", true, this.$t('Alert'));
                }
            }).catch((error) => {
                console.error('Error loading roadmap data:', error);
                this.ShowAlert(this.$t('ErrorLoadingData'), "error", true, this.$t('Alert'));
                this.roadMapData = [];
            }).finally(() => {
                this.isLoading = false;
            });
        },
        TaskColorScheme() {
            this.isRdSetting = false;
            this.IsTaskColorScheme = !this.IsTaskColorScheme;
        },
        SettingsClick() {
            this.IsTaskColorScheme = false;
            this.isRdSetting = !this.isRdSetting;
        },
        handleClickOutside(event) {
            const settingsBtn = event.target.closest('.RM_Setting');
            const taskColorBtn = event.target.closest('.d-inline-block.RM_Setting');
            if (!settingsBtn && !taskColorBtn) {
                this.isRdSetting = false;
                this.IsTaskColorScheme = false;
            }
        },
        onSearchSettings() {
            this.isRdSetting = false;
            this.SearchRoadMap();
        },
        setZoom(zoom) {
            this.activeZoom = zoom;
            // Update date range based on zoom level
            this.updateDateRangeForZoom(zoom);
        },
        updateDateRangeForZoom(zoom) {
            const base = new Date();
            base.setHours(0, 0, 0, 0);
            
            switch(zoom) {
                case 'Week':
                    const baseCopy = new Date(base);
                    const dayOfWeek = baseCopy.getDay();
                    const diffToMonday = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
                    const monday = new Date(baseCopy);
                    monday.setDate(baseCopy.getDate() + diffToMonday);
                    monday.setHours(0, 0, 0, 0);
                    
                    const endDate = new Date(monday);
                    endDate.setMonth(endDate.getMonth() + 2);
                    const lastSunday = new Date(endDate);
                    const lastDayOfWeek = lastSunday.getDay();
                    const diffToSunday = lastDayOfWeek === 0 ? 0 : 7 - lastDayOfWeek;
                    lastSunday.setDate(endDate.getDate() + diffToSunday);
                    lastSunday.setHours(0, 0, 0, 0);
                    
                    this.fromDate = monday;
                    this.toDate = lastSunday;
                    break;
                    
                case 'Month':
                    this.fromDate = new Date(base.getFullYear(), base.getMonth(), 1);
                    this.toDate = new Date(base.getFullYear(), base.getMonth() + 3, 0);
                    break;
                    
                case 'Quarter':
                    // Show 2 quarters (6 months)
                    const quarterStartMonth = Math.floor(base.getMonth() / 3) * 3;
                    this.fromDate = new Date(base.getFullYear(), quarterStartMonth, 1);
                    this.toDate = new Date(base.getFullYear(), quarterStartMonth + 6, 0);
                    break;
                    
                case 'Year':
                    this.fromDate = new Date(base.getFullYear(), 0, 1);
                    this.toDate = new Date(base.getFullYear(), 11, 31);
                    break;
            }
            
            if (this.hasSearched) {
                this.SearchRoadMap();
            }
        },
        ShowUserGuide() {
            this.isUserGuide=true
        }
    },
};
</script>

